#include <stdio.h>
#include <stdlib.h>

typedef struct { long x; long y; } Point;

int main(void) {
    Point a, b;
    if (scanf("%ld %ld %ld %ld", &a.x, &a.y, &b.x, &b.y) != 4) return 1;
    printf("%ld\n", labs(a.x - b.x) + labs(a.y - b.y));
    return 0;
}
